// Gyroid Squish Cube — a rounded cube packed with a WIDE-OPEN gyroid lattice,
// so the woven minimal surface and the gaps straight through every face read
// instantly. The gyroid is a triply-periodic minimal surface (infinite by
// nature); we give it a SLENDER wall thickness and a large cell so only ~3
// cells span each edge, then intersect it with a rounded-box domain so the
// outer silhouette is a soft cube while the interior stays airy and springy.
const { sdf } = api;

const p = api.params({
  edge:  { type: 'number', default: 40,  min: 24, max: 60, step: 1, unit: 'mm', label: 'Cube edge' },
  cell:  { type: 'number', default: 14,  min: 6,  max: 18, step: 0.5, unit: 'mm', label: 'Lattice cell' },
  wall:  { type: 'number', default: 0.5, min: 0.2, max: 1.0, step: 0.05, label: 'Wall density' },
  color: { type: 'color',  default: '#ff5470', label: 'Color' },
});

// Rounded-cube domain: outer extents stay [edge,edge,edge]. Corner radius is
// kept WELL under half the smallest dimension (the roundedBox constraint:
// r < edge/2) and small relative to a cell so the rounding only softens the
// silhouette without eating into the open pores at the corners.
const cornerR = Math.min(p.edge * 0.1, p.edge * 0.45);
const domain = sdf.roundedBox([p.edge, p.edge, p.edge], cornerR);

// gyroid(cell, thickness) is `(|F(k·p)| - thickness)/k`, so the surface is where
// |F| = thickness. F only ranges ~[-1.5, 1.5], so `wall` is a FIELD THRESHOLD,
// not a millimetre width — values ≥1.1 select {|F| < 1.1} ≈ all of space and
// the lattice renders SOLID. The docs' "cellSize/6..cellSize/3" prose misreads
// this; the working examples use gyroid(5, 0.5). Keep `wall` ≈ 0.4–0.7 so the
// two channels ({F > wall}, {F < -wall}) stay open and see-through.
// edgeLength is tied to the CELL (not the threshold) so the woven walls get a
// few triangles across without an enormous mesh.
const edgeLength = Math.max(0.4, p.cell / 16);

const cube = sdf
  .gyroid(p.cell, p.wall)
  .intersect(domain)
  .build({ edgeLength });

// Self-color the whole lattice one vibrant coral. The SDF `.label(name)`
// only tags a paint region (no color arg), so we color via the mesh-side
// `api.label(manifold, name, { color })` after `.build()`.
return api.label(cube, 'lattice', { color: p.color });

